            // LCS-based diff
            $n = count($old_lines);
            $m = count($new_lines);
            $max_len = 2000;
            if ($n > $max_len || $m > $max_len) return ['error' => "Files too large for diff (max $max_len lines). Got: old=$n, new=$m", 'success' => false];
            
            // Build LCS table
            $lcs = array_fill(0, $n + 1, array_fill(0, $m + 1, 0));
